var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"보고드립니다! 합중국에서 무력 충돌 발생! 공군 기술 연구소와의 교신이 불가능합니다!","JPN":"ご報告します！　合衆国で武力衝突が発生！　空軍技術研究所との交信が不可能です！","ENG":"Reporting, sir! Armed conflict in the States! Communication with the Air Force Research Lab is cut!","TWN":"報告！合眾國發生武力衝突！聯絡不上空軍研究所了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"현장에서 건축학부, 철학부 확인! 현지의 요원들이 대응 중이지만 피해를 완전히 억제하긴 어려울 전망입니다!","JPN":"現場で建築学部、哲学部を確認！　現地の要員たちが対応にあたっていますが、被害を完全に防ぐことはできないと予想されます！","ENG":"Department of Architecture and Philosophy spotted on field! Our agents have already engaged in combat, but it will be challenging to contain the damage completely!","TWN":"在現場發現建築學院、哲學院的成員！當地的特務正在處理，但估計很難完全控制損失！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"LAKE-4에서 고준위 침식파 감지! 임계점에 도달하여 CSE 레벨 4로……!","JPN":"LAKE-4で高レベルの侵食波を感知！　臨界点に到達し、CSEレベル4に……！","ENG":"Detecting high-level Corruption ray at LAKE-4! Reached critical point to CSE level 4...!","TWN":"在LAKE-4檢測到高危險級侵蝕波！達到臨界點，CSE等級升至4……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"흠……. 이번 기회에 끝장을 볼 기세로군.","JPN":"ふむ……今回で決着をつけさせんばかりの勢いだな。","ENG":"Hmm... Looks like they are taking this opportunity to really end it.","TWN":"嗯……看這架勢，他們是想趁此機會做個了斷啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서야 티타임을 즐길 겨를도 없겠어.","JPN":"これではティータイムを楽しむ暇もなさそうだ。","ENG":"I guess I won't be able to enjoy my tea today.","TWN":"這樣下去，連喝下午茶的時間都沒有了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"법학부의 존재는 확인됐나?","JPN":"法学部の存在は確認したか？","ENG":"Any sight of the Department of Law?","TWN":"確認到法學院的存在了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"자료 분석 결과, 현재까지는 파악된 바 없습니다. 이번 공세에는 가담하지 않은 모양입니다.","JPN":"資料を分析した結果、今現在では何も把握できていません。今回の攻勢には加わっていない様子です。","ENG":"According to our analysis, not yet, sir. We believe that they didn't take part in this attack.","TWN":"資料分析結果顯示，到目前為止還沒確認。他們好像沒有參與這次攻勢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 걱정거리는 하나 덜었군.","JPN":"よし。心配事が一つ減ったな。","ENG":"Okay. That's one thing less to worry about.","TWN":"很好。煩心事少了一件。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 네…… 이렇게인가?","JPN":"あ、はい……こうかな？","ENG":"Oh, okay. Like this?","TWN":"啊，是……這樣嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"크리스입니다. 무슨 일이세요?","JPN":"クリスです。どうしたんですか？","ENG":"This is Chris. You called?","TWN":"我是克莉絲，你有什麼事嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 수훈자답게 믿음직스러운 목소리군. 지금 어디쯤인가?","JPN":"はは、受勲者らしい頼もしい声だ。今はどの辺かな？","ENG":"Haha. What a trustworthy voice of a war hero. Where are you right now?","TWN":"哈哈哈，不愧是受勳者，聲音聽起來很可靠呢。你現在在哪裡？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어… 미덥지 못한 목소리겠죠. 전설의 첩보원도 나이는 못 이기나 보죠.","JPN":"は……頼りない声の間違いでしょ。伝説の諜報員も歳には勝てないみたいですね。","ENG":"What...? ”Untrustworthy”, you mean. Guess even a legendary spy can't beat age.","TWN":"呵……應該是不可靠才對吧。看來傳說中的特務，也輸給了歲月呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지금 손님들을 태우고 가는 중이에요.","JPN":"今お客さんたちを乗せて向かっているところです。","ENG":"I'm escorting the guests and heading over.","TWN":"我現在正載著客人過去。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사실은 국빈으로 대접해 주길래 영영 눌러앉을까 고민했는데요….","JPN":"本当は国賓として迎えてくれるんだから、そのまま居座ろうかとも思いましたけど……","ENG":"You know, I was considering just slacking off because they treat me like a VIP, but...","TWN":"事實上，因為受到了貴賓待遇，所以我也考慮過要不要永遠待在這裡……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"루이제 아주머니가 인질로 잡혀 있는 이상 어쩔 수 없죠.","JPN":"ルイーゼおばさんが人質になっている以上、仕方ないですね。","ENG":"With them taking Louise hostage, I guess I'll have to play by their rules.","TWN":"既然露易絲阿姨被抓做人質，那就沒辦法了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"일이 잘 풀렸나 보군. 다행일세.","JPN":"うまく行ったようだな。何よりだ。","ENG":"I see things are going well. That's a relief.","TWN":"看來事情很順利啊。真是慶幸。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 너무 흔쾌히 승낙해 줘서 어리둥절하네요. 사전에 뒷돈이라도 먹인 거 아니에요?","JPN":"まあ、逆にすんなりと承諾してくれて戸惑ってますよ。あらかじめ裏金でも渡してたんじゃないですか？","ENG":"Uh, I'm kinda surprised they readily accepted. Was there a back deal that I'm not aware of?","TWN":"嗯，答應得太爽快了，有點讓人摸不著頭腦呢。是不是事先給賄賂了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 갑자기 연락이라니, 좋은 소식은 아니려나.","JPN":"それよりいきなり連絡だなんて、いい知らせではなさそうね。","ENG":"Anyway, why the sudden call? Is there good news you want to tell me?","TWN":"話說回來，你突然聯絡我，應該不是好消息吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};